@media(max-width:1024px){
  .hw{grid-template-columns:1fr;gap:48px;padding:80px 32px 60px}
  .hvis{height:360px}
  .lgrid{grid-template-columns:repeat(2,1fr)}
  .prodgrid{grid-template-columns:1fr}
