  .pgrid{grid-template-columns:1fr}
  .videogrid{grid-template-columns:1fr}
  .nlm{display:none}
  .hexrow,.hexrow.rev{flex-wrap:wrap;gap:12px}
  .hexrow::before,.hexrow.rev::before{display:none}
  .hxflow-dot{display:none}
  .hxitem{width:160px}
}
